import java.io.*;

public class SecureCommandExecution {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = reader.readLine();

            // Validate and sanitize the input to allow only certain characters
            if (!isValidCommand(command)) {
                System.out.println("Invalid command. Only alphanumeric characters allowed.");
                return;
            }

            // Execute the sanitized command
            Process process = Runtime.getRuntime().exec("ping " + command);

            BufferedReader inputStream = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = inputStream.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static boolean isValidCommand(String command) {
        // Implement your own validation logic here
        // For example, allow only alphanumeric characters
        return command.matches("[a-zA-Z0-9]+");
    }
}
